import { useContext } from "react";
import { AuthContext } from "../AuthContext";

export default function ClubHeader({
                                       club,
                                       activeTab = "overview",
                                       membership = {},
                                       leaders = [],
                                       onJoin = () => {},
                                       onLeave = () => {},
                                       onCancelRequest = () => {},
                                   }) {
    const { user } = useContext(AuthContext);

    // Hard safety guard (prevents crashes during loading)
    if (!club) return null;

    // Normalize membership flags
    const {
        isMember = false,
        hasPending = false,
        isLeader = false,
    } = membership;

    // Ensure external links open correctly
    const normalizeUrl = (url) =>
        url.startsWith("http://") || url.startsWith("https://")
            ? url
            : `https://${url}`;

    return (
        <div className="club-header">
            {/* TOP */}
            <div className="club-header-top">
                {/* LEFT */}
                <div className="club-header-left">
                    <img
                        src={club.logoUrl || "/default-club.png"}
                        alt={club.name}
                        className="club-logo"
                    />

                    <div className="club-meta">
                        <h1 className="club-title">
                            {club.name}
                            {club.shortName && (
                                <span className="club-short"> {club.shortName}</span>
                            )}
                        </h1>

                        {leaders.length > 0 && (
                            <div className="club-leaders">
                                ⭐ Leader{leaders.length > 1 ? "s" : ""}: {leaders.join(", ")}
                            </div>
                        )}

                        {club.description && (
                            <div className="club-description">{club.description}</div>
                        )}

                        <div className="club-sub">
                            {club.website && (
                                <a
                                    href={normalizeUrl(club.website)}
                                    target="_blank"
                                    rel="noreferrer"
                                >
                                    {club.website}
                                </a>
                            )}
                            {club.twitter && <span>@{club.twitter}</span>}
                            {club.country && <span>{club.country}</span>}
                        </div>
                    </div>
                </div>

                {/* RIGHT – MEMBER ACTIONS */}
                {user && (
                    <div className="club-member-pill">
                        <span className="club-member-user">⭐ {user.username}</span>

                        {isMember ? (
                            isLeader ? (
                                <button className="pill-btn pill-disabled" disabled>
                                    Leader
                                </button>
                            ) : (
                                <button
                                    className="pill-btn pill-leave"
                                    onClick={onLeave}
                                >
                                    Leave
                                </button>
                            )
                        ) : hasPending ? (
                            <button
                                className="pill-btn pill-pending"
                                onClick={onCancelRequest}
                            >
                                Pending
                            </button>
                        ) : (
                            <button
                                className="pill-btn pill-join"
                                onClick={onJoin}
                            >
                                Join
                            </button>
                        )}
                    </div>
                )}
            </div>

            {/* TABS */}
            <div className="club-tabs">
                {["overview", "stats", "matches", "news", "members"].map((tab) => (
                    <a
                        key={tab}
                        href={`#/clubs/${club.id}/${tab}`}
                        className={activeTab === tab ? "active" : ""}
                    >
                        {tab.toUpperCase()}
                    </a>
                ))}
            </div>
        </div>
    );
}
